{"content":"2097: func TestContext2Apply_import(t *testing.T) {
2098: 	m := testModuleInline(t, map[string]string{
2099: 		"main.tf": `
2100: resource "test_resource" "a" {
2101:   id = "importable"
2102: }
2103: 
2104: import {
2105:   to = test_resource.a
2106:   id = "importable"
2107: }
2108: `,
2109: 	})
2110: 
2111: 	p := testProvider("test")
2112: 	p.GetProviderSchemaResponse = getProviderSchemaResponseFromProviderSchema(&providerSchema{
2113: 		ResourceTypes: map[string]*configschema.Block{
2114: 			"test_resource": {
2115: 				Attributes: map[string]*configschema.Attribute{
2116: 					"id": {
2117: 						Type:     cty.String,
2118: 						Required: true,
2119: 					},
2120: 				},
2121: 			},
2122: 		},
2123: 	})
2124: 	p.PlanResourceChangeFn = func(req providers.PlanResourceChangeRequest) providers.PlanResourceChangeResponse {
2125: 		return providers.PlanResourceChangeResponse{
2126: 			PlannedState: req.ProposedNewState,
2127: 		}
2128: 	}
2129: 	p.ImportResourceStateFn = func(req providers.ImportResourceStateRequest) providers.ImportResourceStateResponse {
2130: 		return providers.ImportResourceStateResponse{
2131: 			ImportedResources: []providers.ImportedResource{
2132: 				{
2133: 					TypeName: "test_instance",
2134: 					State: cty.ObjectVal(map[string]cty.Value{
2135: 						"id": cty.StringVal("importable"),
2136: 					}),
2137: 				},
2138: 			},
2139: 		}
2140: 	}
2141: 	hook := new(MockHook)
2142: 	ctx := testContext2(t, &ContextOpts{
2143: 		Hooks: []Hook{hook},
2144: 		Providers: map[addrs.Provider]providers.Factory{
2145: 			addrs.NewDefaultProvider("test"): testProviderFuncFixed(p),
2146: 		},
2147: 	})
2148: 	plan, diags := ctx.Plan(m, states.NewState(), &PlanOpts{
2149: 		Mode: plans.NormalMode,
2150: 	})
2151: 	assertNoErrors(t, diags)
2152: 
2153: 	_, diags = ctx.Apply(plan, m, nil)
2154: 	assertNoErrors(t, diags)
2155: 
2156: 	if !hook.PreApplyImportCalled {
2157: 		t.Fatalf("PreApplyImport hook not called")
2158: 	}
2159: 	if addr, wantAddr := hook.PreApplyImportAddr, mustResourceInstanceAddr("test_resource.a"); !addr.Equal(wantAddr) {
2160: 		t.Errorf("expected addr to be %s, but was %s", wantAddr, addr)
2161: 	}
2162: 
2163: 	if !hook.PostApplyImportCalled {
