{"content":"114: func (ctx *BuiltinEvalContext) Hook(fn func(Hook) (HookAction, error)) error {
115: 	for _, h := range ctx.Hooks {
116: 		action, err := fn(h)
117: 		if err != nil {
118: 			return err
119: 		}
120: 
121: 		switch action {
122: 		case HookActionContinue:
123: 			continue
124: 		case HookActionHalt:
125: 			// Return an early exit error to trigger an early exit
126: 			log.Printf("[WARN] Early exit triggered by hook: %T", h)
127: 			return nil
128: 		}
129: 	}
130: 
131: 	return nil
132: }
